#include<bits/stdc++.h>
using namespace std;
long long a[1005][1005];
long long dp[1005][1005];
int r;
int vis[1005][1005];
long long maxi;
void dfs(int x,int y){
	if(x<r){
//		cout<<endl;
//		cout<<dp[x+1][y]<<" ";
		vis[x+1][y]++;
		vis[x+1][y+1]++;
		dp[x+1][y]=max(dp[x][y]+a[x+1][y],dp[x+1][y]);
//		cout<<dp[x+1][y]<<" ";
//		cout<<dp[x+1][y+1]<<" ";
		dp[x+1][y+1]=max(dp[x][y]+a[x+1][y+1],dp[x+1][y+1]);
//		cout<<dp[x+1][y+1]<<" ";
		if(vis[x+1][y]==2)
			dfs(x+1,y);
		if(vis[x+1][y+1]==2)
			dfs(x+1,y+1);
	}else{
		maxi=max(dp[x][y],maxi);
		return ;
	}
}
int main()
{

	cin>>r;
	for(int i=1;i<=r;i++){
		for(int j=1;j<=i;j++){
			if(j==1||j==i)vis[i][j]++;
			cin>>a[i][j];
		}
	}
	dp[1][1]=a[1][1];
	dfs(1,1);
	cout<<maxi;//78洛谷
}
